content.text:
:root {
  /* Colors */
  --color-primary: oklch(0.6 0.22 260);
  --color-surface: #1e293b;
  --color-text:    #f8fafc;

  /* Spacing */
  --space-1: 0.25rem;
  --space-2: 0.5rem;
  --space-4: 1rem;
  --space-8: 2rem;

  /* Typography */
  --font-sans: "Inter", system-ui, sans-serif;
  --text-base: 1rem;
  --leading-normal: 1.6;

  /* Borders */
  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-full: 9999px;

  /* Elevation */
  --shadow-sm: 0 1px 2px rgb(0 0 0 / 0.05);
  --shadow-md: 0 4px 12px rgb(0 0 0 / 0.1);
}

.button {
  background-color: var(--color-primary);
  color: var(--color-text);
  padding: var(--space-2) var(--space-4);
  border-radius: var(--radius-md);
  font-family: var(--font-sans);
  box-shadow: var(--shadow-sm);
}

/* With fallback — used if --color-accent is not defined */
.accent-text {
  color: var(--color-accent, var(--color-primary));
}

/* Fallback to a literal value */
.card {
  padding: var(--card-padding, 24px);
}

:root {
  --button-bg: #3b82f6;
  --button-color: white;
}

/* Override for a specific section */
.danger-zone {
  --button-bg: #ef4444;
}

/* Buttons inside .danger-zone get the red bg automatically */
.danger-zone .button {
  background-color: var(--button-bg);  /* #ef4444 */
  color: var(--button-color);          /* white — from :root */
}

/* Buttons outside .danger-zone still get the blue bg */
.normal-section .button {
  background-color: var(--button-bg);  /* #3b82f6 */
}

:root {
  /* Light mode defaults */
  --color-surface:    #ffffff;
  --color-surface-2:  #f8fafc;
  --color-text:       #0f172a;
  --color-text-muted: #64748b;
  --color-border:     #e2e8f0;
  --color-primary:    oklch(0.55 0.24 260);
}

/* Dark mode — override tokens only */
@media (prefers-color-scheme: dark) {
  :root {
    --color-surface:    #0f172a;
    --color-surface-2:  #1e293b;
    --color-text:       #f8fafc;
    --color-text-muted: #94a3b8;
    --color-border:     oklch(0.3 0.02 260 / 0.5);
    --color-primary:    oklch(0.65 0.22 260);
  }
}

/* Manual theme override (class/attribute toggle) */
[data-theme="dark"] {
  --color-surface:    #0f172a;
  --color-surface-2:  #1e293b;
  /* ... */
}

// Read a custom property
const root = document.documentElement;
const primary = getComputedStyle(root)
  .getPropertyValue('--color-primary').trim();

// Set a custom property
root.style.setProperty('--color-primary', 'oklch(0.65 0.22 260)');

// Remove (reset to inherited value)
root.style.removeProperty('--color-primary');

// Per-element override
const card = document.querySelector('.card');
card.style.setProperty('--card-accent', '#10b981');

// button.component.ts
@Component({
  selector: 'app-button',
  template: `<button class="btn"><ng-content /></button>`,
  styles: [`
    .btn {
      background-color: var(--color-primary);
      /* This var() crosses the ViewEncapsulation boundary —
         it reads the closest ancestor's --color-primary */
    }
  `]
})
export class ButtonComponent {}

// theme.service.ts
@Injectable({ providedIn: 'root' })
export class ThemeService {
  readonly theme = signal<'light' | 'dark'>('light');

  constructor() {
    effect(() => {
      document.documentElement.dataset['theme'] = this.theme();
    });
  }
}

/* card.component.scss */
:host {
  /* Defaults — consumers override via parent element or inline style */
  --card-bg: var(--color-surface, #1e293b);
  --card-padding: var(--space-6, 1.5rem);
  --card-radius: var(--radius-md, 8px);
  --card-border: 1px solid var(--color-border, transparent);

  display: block;
  background: var(--card-bg);
  padding: var(--card-padding);
  border-radius: var(--card-radius);
  border: var(--card-border);
}

@property --progress {
  syntax: "<number>";       /* type — number, color, length, percentage, etc. */
  initial-value: 0;
  inherits: false;          /* don't inherit to descendants */
}

.progress-bar {
  --progress: 0;
  background: conic-gradient(
    oklch(0.6 0.22 260) calc(var(--progress) * 1%),
    #1e293b 0%
  );
  border-radius: 50%;
  transition: --progress 500ms ease;
}

.progress-bar.complete {
  --progress: 100;
}

:root {
  /* === Primitive tokens === */
  /* Color primitives */
  --blue-400: oklch(0.65 0.20 260);
  --blue-500: oklch(0.58 0.22 260);
  --blue-600: oklch(0.51 0.22 260);
  --slate-50:  oklch(0.97 0.01 260);
  --slate-900: oklch(0.17 0.02 260);

  /* Spacing primitives */
  --size-1: 4px;
  --size-2: 8px;
  --size-4: 16px;
  --size-6: 24px;
  --size-8: 32px;

  /* === Semantic tokens === */
  /* Use these in component styles, not primitives */
  --color-primary:         var(--blue-500);
  --color-primary-hover:   var(--blue-600);
  --color-background:      var(--slate-900);
  --color-text:            var(--slate-50);

  --space-component-padding: var(--size-4);
  --space-section-gap:       var(--size-8);
}

/* Dark mode only needs to remap semantic tokens */
@media (prefers-color-scheme: dark) {
  :root {
    --color-background: var(--slate-900);
    --color-text:       var(--slate-50);
  }
}

:root {
  --grid-columns: 12;
  --grid-gap: 24px;
  --container-width: 1200px;
}

.column-4 {
  /* 4 out of 12 columns */
  width: calc(
    (100% - var(--grid-gap) * (var(--grid-columns) - 1))
    / var(--grid-columns)
    * 4
    + var(--grid-gap) * 3
  );
}

/* Spacing scale */
:root { --space-unit: 4px; }

.gap-2 { gap: calc(var(--space-unit) * 2); }   /* 8px */
.gap-4 { gap: calc(var(--space-unit) * 4); }   /* 16px */
.gap-8 { gap: calc(var(--space-unit) * 8); }   /* 32px */
